// GoldenTest tests compare generated output with expected golden files
// to ensure template output is deterministic and correct.

func TestGoldenHeader(t *testing.T) {
	tm, err := NewTemplateManager()
	assert.NoError(t, err)

	data := HeaderData{
		SetName: "dev",
		Shell:   "bash",
	}

	output, err := tm.ExecuteHeader(data)
	assert.NoError(t, err)

	// Expected header should contain these lines
	expectedLines := []string{
		"# kfg shell integration",
		"# set: dev",
		"# shell: bash",
		"# Generated by kfg shell compiler",
	}

	for _, line := range expectedLines {
		assert.Contains(t, output, line, "header should contain expected line")
	}
}

